import streamlit as stfrom sqlalchemy import textclass Database:    def __init__(self):        # Note that xai_db_conn is available secrets.toml        self.conn = st.connection("xai_db_conn",                                   type="sql",                                  pool_pre_ping=True,  # Checks if connection is alive before using it                                  pool_recycle=300,                                      pool_timeout=30                                 )    def execute_query(self, query, params={}, write=False):        """        Params:         query: the SQL query string you want to run          params: a dictionary (defaulting to an empty one) that maps any parameters (variables)                  in the query text to the value we want to substitute them with         write: a Boolean flag that tells the method whether this is a write                operation (like INSERT, UPDATE, or DELETE) or not (SELECT)         """        with self.conn.session as session:            try:                # Get the qurey resul                result = session.execute(text(query), params)                if write:                    session.commit()                return result.fetchall()            except Exception:                if write:                    session.rollback()                raise